window.YPP.features.SubscriptionManager=class{constructor(){this.logger=window.YPP.Utils||console,this.groups={},this.channels=[],this.isInitialized=!1,this.STORAGE_KEY="yt_subscription_groups"}async init(){this.isInitialized||(await this.loadGroups(),window.YPP.Utils.log("Initialized Subscription Manager","SubManager"),this.isInitialized=!0)}async loadGroups(){try{const s=await chrome.storage.local.get(this.STORAGE_KEY);this.groups=s[this.STORAGE_KEY]||{},window.YPP.Utils.log("Loaded groups","SubManager","debug")}catch(s){window.YPP.Utils.log(`Failed to load groups: ${s==null?void 0:s.message}`,"SubManager","error")}}async saveGroups(){try{await chrome.storage.local.set({[this.STORAGE_KEY]:this.groups}),window.YPP.Utils.log("Saved groups","SubManager","debug")}catch(s){window.YPP.Utils.log(`Failed to save groups: ${s==null?void 0:s.message}`,"SubManager","error")}}createGroup(s){return this.groups[s]?(window.YPP.Utils.log(`Group "${s}" already exists.`,"SubManager","warn"),!1):(this.groups[s]=[],this.saveGroups(),!0)}deleteGroup(s){return this.groups[s]?(delete this.groups[s],this.saveGroups(),!0):!1}addChannelToGroup(s,t){return this.groups[s]?this.groups[s].some(i=>i.id===t.id)?!1:(this.groups[s].push(t),this.saveGroups(),!0):!1}removeChannelFromGroup(s,t){if(!this.groups[s])return!1;const i=this.groups[s].length;return this.groups[s]=this.groups[s].filter(r=>r.id!==t),this.groups[s].length!==i?(this.saveGroups(),!0):!1}getGroups(){return this.groups}getChannelsInGroup(s){return this.groups[s]||[]}};
